DROP TABLE IF EXISTS `resident`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `resident` (
  `resident_id` bigint NOT NULL AUTO_INCREMENT COMMENT '居民主键ID',
  `phone` varchar(11) NOT NULL COMMENT '登录手机号，唯一',
  `password` varchar(64) NOT NULL COMMENT '加密存储密码',
  `nickname` varchar(50) DEFAULT '',
  `building` varchar(32) DEFAULT '' COMMENT '居住楼栋',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '账号状态 0禁用 1正常',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '注册时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '信息更新时间',
  PRIMARY KEY (`resident_id`),
  UNIQUE KEY `uk_phone` (`phone`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='居民用户表';
