CREATE TABLE `system_notice` (
  `notice_id` bigint NOT NULL AUTO_INCREMENT COMMENT '公告ID',
  `admin_id` bigint NOT NULL COMMENT '发布管理员ID',
  `title` varchar(100) NOT NULL COMMENT '公告标题',
  `content` text NOT NULL COMMENT '科普正文',
  `show_miniprogram` tinyint NOT NULL DEFAULT '1' COMMENT '小程序是否展示 0隐藏 1展示',
  `publish_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`notice_id`),
  KEY `idx_admin` (`admin_id`),
  CONSTRAINT `fk_notice_admin` FOREIGN KEY (`admin_id`) REFERENCES `administrator` (`admin_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='垃圾分类科普公告表';
