DROP TABLE IF EXISTS `throw_rule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `throw_rule` (
  `rule_id` bigint NOT NULL AUTO_INCREMENT COMMENT '规则主键ID',
  `category_id` bigint NOT NULL COMMENT '关联四大类ID',
  `garbage_name` varchar(50) NOT NULL COMMENT '垃圾标准名称',
  `alias` varchar(100) DEFAULT '' COMMENT '别名，逗号分隔',
  `tip` text COMMENT '投放预处理规范',
  `confuse_tip` text COMMENT '易混淆垃圾区分提示',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`rule_id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_name` (`garbage_name`),
  CONSTRAINT `fk_rule_category` FOREIGN KEY (`category_id`) REFERENCES `garbage_category` (`category_id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='细分垃圾投放规则表';
